    @EventTarget
    public void onWorld(WorldEvent event) {
        clickedContainers.clear();
        playerClickedContainers.clear();
        if (Client.moduleManager.getModule(HackDefender.class).isEnabled() && HackDefender.addons.get("Cherish IRC"))
            updateCoolUser();
        tags.clear();
        isMark = false;
    }

    @EventTarget
    public void onTick(TickEvent event) {
        updatePlayerData();
        if (Client.SYSTEM == Client.Systems.WINDOWS && Client.moduleManager.getModule(MusicInfo.class).getState()) {
            updateMusicInfo();
        } else {
            curMusicinfo = new Loader.MediaInfo("Unsupported System Operation", "Error", "Error", "Error", 0, "\n", Loader.State.Unknown, false, "Error");
        }
    }

    public static void updatePlayerData() {
        if (mc.player != null && mc.world != null) {
            x = mc.player.getX();
            y = mc.player.getY();
            z = mc.player.getZ();
            onGround = mc.player.isOnGround();
            inAir = !onGround;
        }
    }

    @EventTarget
    public void onMotion(MotionEvent event) {
        if (mc.player == null || mc.world == null) return;

        if (event.eventState == CancellableEvent.EventState.PRE) {
            ticksSinceFlag++;
            if (mc.player.age <= 1)
                Client.getInstance().getEventManager().call(new RespawnEvent());
        }

        if (BedBreaker.targetX == null) {
            BedBreaker.updateClosestBlockPos();
        }

        for (PlayerEntity player : new ArrayList<>(mc.world.getPlayers())) {
        }
    }

    private void checkAndNotifyItem(PlayerEntity player, Set<String> playerTags, String itemName,
                                    Supplier<Boolean> condition) {
        if (condition.get() && !playerTags.contains(itemName)) {
            NotificationManager.post(NotificationType.WARRING, player.getName().getString() + " is holding " + itemName + "!");
            playerTags.add(itemName);
        }
    }

    @SuppressWarnings("unused")
    @EventTarget
    public void onReceiveMessage(ReceiveMessageEvent event) {
        String message = event.getMessage().getString();
        if (message.contains("来升级，使自身和队伍变得更强。") || message.contains("Protect your bed and destroy the enemy beds.") || message.contains("Upgrade yourself and your team by collecting")) {
            BedBreaker.targetX = BedBreaker.targetZ = null;
        }
    }

    @NativeObfuscation
    private static void updateCoolUser() {
        userData.clear();
        String res = sendHttpRequest("http://103.40.14.185:27669/api/chipscat1337");

        if (res != null) {
            if (res.contains("No one is online now")) return;

            String processedRes;
            if (!res.trim().startsWith("[")) {
                processedRes = "[" + res.replace("}{", "},{") + "]";
            } else {
                processedRes = res;
            }
            try {
                Gson gson = new Gson();
                JsonArray array = gson.fromJson(processedRes, JsonArray.class);

                for (JsonElement element : array) {
                    JsonObject userObject = element.getAsJsonObject();
                    String ign = userObject.get("inGame").getAsString();
                    String name = userObject.get("username").getAsString();
                    String client = userObject.get("client").getAsString();
                    boolean beta = userObject.get("beta").getAsBoolean();

                    userData.put(ign, new UserData(ign, name, client, beta));
                }
            } catch (Exception e) {
                System.err.println("Failed to parse user data");
            }
        }
    }

    public static boolean isCoolUser(String ign) {
        if (userData == null) return false;
        return userData.containsKey(ign);
    }

    public static boolean clientOnGround() {
        if (mc.player == null) return false;
        return packetOnGround && mc.player.onGround;
    }



    @EventTarget
    public void onAttack(AttackEvent event) {
        serverSprint = false;
    }

    @EventTarget
    public void onPacket(PacketEvent event) {
        if (mc.player == null || mc.world == null) return;

        if (event.packetState == CancellableEvent.PacketState.SEND) {
            if (event.packet instanceof ClientCommandC2SPacket packet) {
                if (packet.getMode() == ClientCommandC2SPacket.Mode.START_SPRINTING) {
                    realSprint = true;
                    serverSprint = true;
                }
                if (packet.getMode() == ClientCommandC2SPacket.Mode.STOP_SPRINTING) {
                    realSprint = false;
                    serverSprint = false;
                }
            }

            if (event.packet instanceof PlayerMoveC2SPacket packet) {
                packetOnGround = packet.isOnGround();
            }

            /// By clicked packet
            if (event.packet instanceof PlayerInteractBlockC2SPacket packet) {
                BlockPos pos = packet.getBlockHitResult().getBlockPos();
                BlockEntity entity = mc.world.getBlockEntity(pos);

                clickedContainers.add(entity);
                playerClickedContainers.add(entity);
            }
        }

        if (event.packetState == CancellableEvent.PacketState.RECEIVE) {
            if (event.packet instanceof PlayerPositionLookS2CPacket) {
                ticksSinceFlag = 0;
            }

            /// By Sound
            if (event.packet instanceof PlaySoundS2CPacket packet) {
                BlockPos pos = new BlockPos((int) packet.getX(), (int) packet.getY(), (int) packet.getZ());
                BlockEntity entity = mc.world.getBlockEntity(pos);

                clickedContainers.add(entity);
            }

            /// By BlockEvent
            if (event.packet instanceof BlockEventS2CPacket packet) {
                BlockEntity entity = mc.world.getBlockEntity(packet.getPos());

                clickedContainers.add(entity);

            }

            /// By Entity refresh
            if (event.packet instanceof EntitySpawnS2CPacket packet) {
                BlockPos pos = new BlockPos((int) packet.getX(), (int) packet.getY(), (int) packet.getZ());
                BlockEntity entity = mc.world.getBlockEntity(pos);

                clickedContainers.add(entity);
            }

            if (event.packet instanceof PlayerPositionLookS2CPacket s08) {
                final double distance = mc.player.squaredDistanceTo(s08.change().position().getX(), s08.change().position().getY(), s08.change().position().getZ());

                if (distance > 40) {
                    selfBedPos = new Vec3d(s08.change().position().getX(), s08.change().position().getY(), s08.change().position().getZ());
                    isMark = true;
                }
            }
        }
    }

    public static class UserData {
        public String ign;
        public String name;
        public String client;
        public boolean beta;

        public UserData(String ign, String name, String client, boolean beta) {
            this.ign = ign;
            this.name = name;
            this.client = client.substring(0, 1).toUpperCase() + client.substring(1).toLowerCase();
            this.beta = beta;
        }
    }

    public static String sendHttpRequest(String targetUrl) {
        try {
            URL url = new URL(targetUrl);
            HttpURLConnection connection = (HttpURLConnection) url.openConnection();

            connection.setRequestMethod("GET");
            connection.setConnectTimeout(5000);
            connection.setReadTimeout(5000);

            int responseCode = connection.getResponseCode();
            if (responseCode == HttpURLConnection.HTTP_OK) { // 成功响应
                BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream(), "UTF-8"));
                String inputLine;
                StringBuilder response = new StringBuilder();

                while ((inputLine = in.readLine()) != null) {
                    response.append(inputLine);
                }
                in.close();

                return response.toString();
            } else {
                System.out.println("GET request failed. Response Code: " + responseCode);
                return null;
            }
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

