    // 缓存纹理的映射，键是字符串，值是纹理标识符
    private static Map<String, Identifier> texCache = new HashMap<>();

    // 占位纹理的位置标识
    private static Identifier placeholderTextureLocation;

    // 上次用于生成纹理的键
    private static String lastTexKey;

    // 上次用于生成纹理的图像引用
    private static BufferedImage lastImageRef;

    // 缓存的纹理对象
    private static NativeImageBackedTexture cachedTexture;

    // 缓存的纹理位置标识
    private static Identifier cachedTextureLocation;

    public static Identifier getCoverTexture(Loader.MediaInfo musicInfo, boolean force) {
        String key = (musicInfo.title() == null ? "" : musicInfo.title()) + "|" + (musicInfo.artist() == null ? "" : musicInfo.artist());

        // 从 base64 数据获取图像
        BufferedImage currentImage = base64ToBufferedImage(musicInfo.base64());

        boolean needRebuild = force || !key.equals(lastTexKey) || currentImage != lastImageRef;

        if (!needRebuild) {
            Identifier hit = texCache.get(key);
            if (hit != null) return hit;
        }

        Identifier out;
        if (currentImage != null) {
            out = createOrUpdateDynamicTexture(currentImage);
        } else {
            if (placeholderTextureLocation == null) {
                placeholderTextureLocation = createPlaceholderTexture(58, 58, new Color(30, 30, 30, 255));
            }
            out = placeholderTextureLocation;
        }

        texCache.put(key, out);
        lastTexKey = key;
        lastImageRef = currentImage;
        return out;
    }

    private static Identifier createOrUpdateDynamicTexture(BufferedImage src) {
        // 清理旧纹理
        if (cachedTexture != null) {
            cachedTexture.close();
            cachedTexture = null;
        }
        if (cachedTextureLocation != null) {
            mc.getTextureManager().destroyTexture(cachedTextureLocation);
            cachedTextureLocation = null;
        }

        BufferedImage prepared = ensureARGB(src);

        // 使用新的纹理 API
        NativeImage nativeImage = bufferedImageToNativeImage(prepared);
        cachedTexture = new NativeImageBackedTexture(nativeImage);

        cachedTextureLocation = Identifier.of("epsilon", "music_cover_" + System.nanoTime());
        mc.getTextureManager().registerTexture(cachedTextureLocation, cachedTexture);
        return cachedTextureLocation;
    }

    // 将 BufferedImage 转换为 NativeImage
    private static NativeImage bufferedImageToNativeImage(BufferedImage image) {
        int width = image.getWidth();
        int height = image.getHeight();
        NativeImage nativeImage = new NativeImage(NativeImage.Format.RGBA, width, height, false);

        for (int x = 0; x < width; x++) {
            for (int y = 0; y < height; y++) {
                int argb = image.getRGB(x, y);
                int a = (argb >> 24) & 0xFF;
                int r = (argb >> 16) & 0xFF;
                int g = (argb >> 8) & 0xFF;
                int b = argb & 0xFF;

                // 尝试交换 R 和 B 通道
                int color = (a << 24) | (b << 16) | (g << 8) | r;  // ABGR 顺序
                nativeImage.setColor(x, y, color);
            }
        }

        return nativeImage;
    }

    private static BufferedImage ensureARGB(BufferedImage img) {
        if (img != null && img.getType() == BufferedImage.TYPE_INT_ARGB) return img;
        if (img == null) return null;
        BufferedImage out = new BufferedImage(img.getWidth(), img.getHeight(), BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = out.createGraphics();
        g.drawImage(img, 0, 0, null);
        g.dispose();
        return out;
    }

    private static Identifier createPlaceholderTexture(int w, int h, Color c) {
        BufferedImage bi = new BufferedImage(w, h, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = bi.createGraphics();
        g.setColor(c);
        g.fillRect(0, 0, w, h);
        g.dispose();

        NativeImage nativeImage = bufferedImageToNativeImage(bi);
        NativeImageBackedTexture texture = new NativeImageBackedTexture(nativeImage);

        Identifier location = Identifier.of("epsilon", "music_placeholder");
        mc.getTextureManager().registerTexture(location, texture);
        return location;
    }

    //666这个入发代码不发全搞半天还得自己拼
    private static BufferedImage base64ToBufferedImage(String base64) {
        if (base64 == null || base64.isEmpty()) {
            return null;
        }

        try {
            // 移除可能的 Base64 前缀（如 "data:image/jpeg;base64,"）
            String base64Data = base64;
            if (base64.contains(",")) {
                base64Data = base64.split(",")[1];
            }

            // 解码 Base64
            byte[] imageBytes = Base64.getDecoder().decode(base64Data);
            ByteArrayInputStream bis = new ByteArrayInputStream(imageBytes);

            // 转换为 BufferedImage
            BufferedImage image = ImageIO.read(bis);
            bis.close();

            return image;
        } catch (Exception e) {
            System.err.println("Failed to convert base64 to image: " + e.getMessage());
            return null;
        }
    }
